def check_parking(attrs):
    if not attrs:
        return False
    bike = attrs.get('BikeParking')
    has_bike = bike and str(bike).lower() == 'true'

    business = attrs.get('BusinessParking')
    has_business = False
    if business and business != 'None':
        if isinstance(business, str):
            has_business = 'True' in business
        elif isinstance(business, dict):
            has_business = any(business.values())

    return has_bike or has_business

with_parking = []
for biz in business_data:
    if check_parking(biz.get('attributes')):
        with_parking.append(biz['business_id'])

print('Businesses with parking:', len(with_parking))
print('__RESULT__:')
print(json.dumps({'count': len(with_parking), 'businesses': with_parking}))"}

